import React, { useState, useEffect } from "react";
import "./Placement.css";

export default function Placement() {
  const role = localStorage.getItem("role");
  const [posts, setPosts] = useState([]);
  const [newPost, setNewPost] = useState({ title: "", company: "", link: "" });

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("placements")) || [];
    setPosts(stored);
  }, []);

  function handleAdd() {
    const updated = [...posts, newPost];
    localStorage.setItem("placements", JSON.stringify(updated));
    setPosts(updated);
    setNewPost({ title: "", company: "", link: "" });
  }

  function handleDelete(index) {
    const updated = posts.filter((_, i) => i !== index);
    localStorage.setItem("placements", JSON.stringify(updated));
    setPosts(updated);
  }

  return (
    <div className="placement-container">
      <h1>🎯 Placement Opportunities</h1>

      {(role === "admin" || role === "hr") && (
        <div className="add-form">
          <input
            type="text"
            placeholder="Title"
            value={newPost.title}
            onChange={(e) => setNewPost({ ...newPost, title: e.target.value })}
          />
          <input
            type="text"
            placeholder="Company"
            value={newPost.company}
            onChange={(e) =>
              setNewPost({ ...newPost, company: e.target.value })
            }
          />
          <input
            type="url"
            placeholder="Apply Link"
            value={newPost.link}
            onChange={(e) => setNewPost({ ...newPost, link: e.target.value })}
          />
          <button onClick={handleAdd}>Add Placement</button>
        </div>
      )}

      <div className="posts-list">
        {posts.length === 0 ? (
          <p>No placements available.</p>
        ) : (
          posts.map((post, i) => (
            <div className="post-card" key={i}>
              <h3>{post.title}</h3>
              <p><strong>Company:</strong> {post.company}</p>
              <a href={post.link} target="_blank" rel="noreferrer">Apply</a>
              {role === "admin" && (
                <button onClick={() => handleDelete(i)}>Delete</button>
              )}
            </div>
          ))
        )}
      </div>
    </div>
  );
}
